"use client";

import Link from "next/link";
import { useEffect, useRef, useState } from "react";
import { Building2, LogOut, Settings, User } from "lucide-react";
import { DEMO_PROFILE_USER } from "@stockright/shared/demo";

const STROKE = 2;

function parseProfileSubtitle(subtitle: string): { role: string; warehouse: string } {
  const parts = subtitle.split("·").map((s) => s.trim());
  if (parts.length >= 2) {
    return { role: parts[0] ?? "", warehouse: parts.slice(1).join(" · ") };
  }
  return { role: subtitle, warehouse: "" };
}

export function UserAccountMenu() {
  const [open, setOpen] = useState(false);
  const wrapRef = useRef<HTMLDivElement>(null);
  const { role, warehouse } = parseProfileSubtitle(DEMO_PROFILE_USER.subtitle);

  useEffect(() => {
    if (!open) return;
    function handlePointerDown(e: PointerEvent) {
      if (wrapRef.current && !wrapRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener("pointerdown", handlePointerDown);
    return () => document.removeEventListener("pointerdown", handlePointerDown);
  }, [open]);

  return (
    <div ref={wrapRef} className="relative">
      <button
        type="button"
        className="flex size-9 shrink-0 items-center justify-center rounded-full border border-[var(--border-default)] bg-[var(--brand-subtle)] font-[family-name:var(--font-display)] text-[14px] font-semibold text-[var(--brand-text)] transition-opacity hover:opacity-90 focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-[var(--focus-ring)]"
        aria-expanded={open}
        aria-haspopup="menu"
        aria-label="Account menu"
        onClick={() => setOpen((v) => !v)}
      >
        {DEMO_PROFILE_USER.initials}
      </button>

      {open && (
        <div
          role="menu"
          className="absolute right-0 top-[calc(100%+8px)] z-50 w-64 rounded-[var(--radius-lg)] border border-[var(--border-default)] bg-[var(--bg-surface)] py-2 shadow-[var(--shadow-2)]"
        >
          <div className="border-b border-[var(--border-default)] px-3 py-2.5">
            <div className="flex items-start gap-2">
              <User className="mt-0.5 size-4 shrink-0 text-[var(--text-tertiary)]" strokeWidth={STROKE} aria-hidden />
              <div className="min-w-0">
                <p className="text-[14px] font-semibold text-[var(--text-primary)]">{DEMO_PROFILE_USER.name}</p>
                <p className="text-[12px] text-[var(--text-secondary)]">{role}</p>
              </div>
            </div>
            <div className="mt-2 flex items-start gap-2 pl-6">
              <Building2 className="mt-0.5 size-4 shrink-0 text-[var(--text-tertiary)]" strokeWidth={STROKE} aria-hidden />
              <p className="text-[12px] text-[var(--text-secondary)]">{warehouse || "—"}</p>
            </div>
          </div>
          <Link
            href="/settings"
            role="menuitem"
            className="flex items-center gap-2 px-3 py-2.5 text-[14px] text-[var(--text-primary)] hover:bg-[var(--bg-subtle)] focus-visible:bg-[var(--bg-subtle)] focus-visible:outline-none"
            onClick={() => setOpen(false)}
          >
            <Settings className="size-4 text-[var(--text-tertiary)]" strokeWidth={STROKE} aria-hidden />
            Preferences
          </Link>
          <button
            type="button"
            role="menuitem"
            className="flex w-full items-center gap-2 px-3 py-2.5 text-left text-[14px] text-[var(--outward)] hover:bg-[var(--bg-subtle)] focus-visible:bg-[var(--bg-subtle)] focus-visible:outline-none"
            onClick={() => setOpen(false)}
          >
            <LogOut className="size-4" strokeWidth={STROKE} aria-hidden />
            Log out
          </button>
        </div>
      )}
    </div>
  );
}
