"use client";

import Link from "next/link";
import Image from "next/image";
import { usePathname } from "next/navigation";
import { LayoutDashboard, Package, Users, Banknote, UserCircle } from "lucide-react";
import { cn } from "@/lib/utils";

const navItems = [
  { href: "/", label: "Home", icon: LayoutDashboard },
  { href: "/stock", label: "Stock", icon: Package },
  { href: "/parties", label: "Parties", icon: Users },
  { href: "/money", label: "Money", icon: Banknote },
  { href: "/settings", label: "Preferences", icon: UserCircle },
] as const;

export function SideNav() {
  const pathname = usePathname() ?? "";

  return (
    <nav
      className="flex flex-col overflow-y-auto border-r border-[var(--border-default)] bg-[var(--bg-subtle)]"
      style={{ width: "var(--sidenav-width)" }}
    >
      <div className="border-b border-[var(--border-default)] px-4 py-5">
        <Image src="/wordmark.svg" alt="StockRight" width={120} height={24} priority />
      </div>
      <div className="flex flex-1 flex-col gap-0.5 px-2 py-4">
        {navItems.map(({ href, label, icon: Icon }) => {
          const base = pathname.replace(/\/$/, "") || "/";
          const hrefNorm = href.replace(/\/$/, "") || "/";
          const isActive =
            hrefNorm === "/"
              ? base === "/"
              : base === hrefNorm || base.startsWith(`${hrefNorm}/`);
          return (
            <Link
              key={href}
              href={href}
              className={cn(
                "flex items-center gap-2.5 rounded-[10px] px-3 py-2.5 text-[13px] font-medium leading-snug transition-colors duration-[var(--duration-fast)]",
                isActive
                  ? "bg-[var(--brand-subtle)] font-semibold text-[var(--brand-text)]"
                  : "text-[var(--text-secondary)] hover:bg-[var(--bg-inset)] hover:text-[var(--text-primary)]"
              )}
            >
              <Icon size={18} strokeWidth={2} className="shrink-0" />
              {label}
            </Link>
          );
        })}
      </div>
    </nav>
  );
}
